import React, { useRef, useState } from 'react';

function VideoThumbnail({ videoUrl }) {
  const [thumbnail, setThumbnail] = useState(null);
  const videoRef = useRef(null);

  const generateThumbnail = () => {
    const video = videoRef.current;
    if (!video) return;

    video.currentTime = 1;
    video.onseeked = () => {
      const canvas = document.createElement('canvas');
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      canvas.getContext('2d').drawImage(video, 0, 0, canvas.width, canvas.height);
      setThumbnail(canvas.toDataURL());
    };
  };

  return (
    <div style={{ width: '100%', height: '100%' }}>
      <video
        ref={videoRef}
        src={videoUrl}
        style={{ display: 'none' }}
        onLoadedMetadata={generateThumbnail}
        crossOrigin="anonymous"
      />
      {thumbnail ? (
        <img src={thumbnail} alt="Thumbnail" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
      ) : (
        <div style={{ fontSize: 48, display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>🎬</div>
      )}
    </div>
  );
}
export default HomePage;
